%[text] # 例4.0（画像のDFT）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example04_10"; % mfilename

imgname = "msipimg08";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');
%%
%[text] ## 原画像の表示
figure(1) %[output:770b8129]
imshow(X) %[output:770b8129]
title('原画像')  %[output:770b8129]
%%
%[text] ## 分布として表示
figure(2) %[output:62dacd59]
h = surf(X); %[output:62dacd59]
colormap("gray") %[output:62dacd59]
h.EdgeColor = "none"; %[output:62dacd59]

shading interp %[output:62dacd59]
daspect([8 8 1]) %[output:62dacd59]
ax = gca;
ax.FontSize = 18; %[output:62dacd59]
ax.YDir = 'reverse'; %[output:62dacd59]
ax.XTick = 0:20:100; %[output:62dacd59]
ax.YTick = 0:20:100; %[output:62dacd59]
ax.ZTick = 0:1; %[output:62dacd59]
ax.Color = 'none'; %[output:62dacd59]
fg = gcf;
fg.Color = 'none'; %[output:62dacd59]
set(fg,'Renderer','opengl');  %[output:62dacd59]
xlabel("$q_\mathrm{h}$","Interpreter","latex","FontSize",20); %[output:62dacd59]
ylabel("$q_\mathrm{v}$","Interpreter","latex","FontSize",20); %[output:62dacd59]
zlabel("$u(\mathbf{q})$","Interpreter","latex","FontSize",20); %[output:62dacd59]

exportgraphics(fg,fullfile(resfolder,"fig04-01a.png")); %,'BackgroundColor','none','ContentType','image') %[output:62dacd59]
%%
%[text] ## 振幅スペクトルの表示
figure(3) %[output:49820ed6]
Y = fftshift((abs(fft2(X,128,128))));
[Fx,Fy] = meshgrid(-1:2/128:1-2/128,-1:2/128:1-2/128);
h = surf(Fx,Fy,Y); %[output:49820ed6]
A = 10*log10(h.CData);
h.CData = (A-min(A(:)))/(max(A(:))-min(A(:))); %[output:49820ed6]
colormap("gray") %[output:49820ed6]
h.EdgeColor = "none"; %[output:49820ed6]

shading interp %[output:49820ed6]
daspect([1 1 12000]) %[output:49820ed6]
ax = gca;
ax.FontSize = 18; %[output:49820ed6]
ax.YDir = 'reverse'; %[output:49820ed6]
ax.XTick = -1:1; %[output:49820ed6]
ax.XTickLabel = {"-\pi/\Delta_h","0","\pi/\Delta_h"}; %[output:49820ed6]
ax.YTick = -1:1; %[output:49820ed6]
ax.YTickLabel = {"-\pi/\Delta_v","0","\pi/\Delta_v"}; %[output:49820ed6]
ax.ZTick = 0; %[output:49820ed6]
ax.Color = 'none'; %[output:49820ed6]
fg = gcf;
fg.Color = 'none'; %[output:49820ed6]
set(fg,'Renderer','opengl');  %[output:49820ed6]
xlabel("$\nu_\mathrm{h}$","Interpreter","latex","FontSize",20); %[output:49820ed6]
ylabel("$\nu_\mathrm{v}$","Interpreter","latex","FontSize",20); %[output:49820ed6]
zlabel("$|\tilde{u}(\mathbf{\nu})|$","Interpreter","latex","FontSize",20); %[output:49820ed6]

exportgraphics(fg,fullfile(resfolder,"fig04-01b.png")); %,'BackgroundColor','none','ContentType','image') %[output:49820ed6]
%%
%[text] ## 要素波形の表示
[Qx,Qy] = meshgrid(-0.5:1/128:0.5-1/128,-0.5:1/128:0.5-1/128);

idx = 1;
for iv = 0:2 %[output:group:02460b60]
    for ih = 0:2
        figure(3+idx) %[output:070a6477] %[output:15d60e49] %[output:7b850f9d] %[output:3b917fb0] %[output:2a0d6640] %[output:056b1306] %[output:4587de56] %[output:03becf52] %[output:24c1021f]
        nuv = 2*pi*iv;
        nuh = 2*pi*ih;

        b = @(qv,qh) cos(nuv.*qv+nuh.*qh);

        h = surf(Qx,Qy,b(Qy,Qx)); %[output:070a6477] %[output:15d60e49] %[output:7b850f9d] %[output:3b917fb0] %[output:2a0d6640] %[output:056b1306] %[output:4587de56] %[output:03becf52] %[output:24c1021f]
        axis off
        daspect([1 1 64])
        colormap("gray")
        h.EdgeColor = "none";
        shading interp
        idx = idx + 1;
        ax = gca;
        ax.Color = 'none';
        fg = gcf;
        fg.Color = 'none';
        set(fg,'Renderer','opengl');
        exportgraphics(fg,fullfile(resfolder,"fig04-01c"+"_"+num2str(iv)+"_"+num2str(ih)+".png")); %,'BackgroundColor','none','ContentType','image')

    end
end %[output:group:02460b60]
